# efficient iterative variant
def T(n: int, k: int) -> int:
    if k == 0: return 1 if n == 0 else 0
    q, p = 1, 1
    for m in range(1, k):
        p *= -k
        q = p + m * q
    nk = 1
    for _ in range(n - k): nk *= k
    sign = 1 if k % 2 == 1 else -1
    return sign * nk * q
for n in range(10): print([T(n, k) for k in range(0, n+1)])

